NVIDIA_NIM_KEY = os.environ.get("NVIDIA_NIM_KEY", NVIDIA_NIM_KEY)
CUSTOM_API_KEY = os.environ.get("CUSTOM_API_KEY", CUSTOM_API_KEY)

# Embedded HTML (Base64 encoded to prevent escaping issues)
HTML_BASE64 = """"""

HTML_CONTENT = base64.b64decode(HTML_BASE64).decode('utf-8')

# Inject default API key into the frontend settings at load time
HTML_CONTENT = HTML_CONTENT.replace("apiKey: ''", f"apiKey: '{GEMINI_API_KEY}'")

# =========================================================================
# STARLETTE / ASGI PROXY & SERVICE ENGINE
# =========================================================================
from starlette.applications import Starlette
from starlette.routing import Route
from starlette.responses import Response, JSONResponse, HTMLResponse
from starlette.endpoints import HTTPEndpoint

class StarletteProxyEndpoint(HTTPEndpoint):
    async def options(self, request):
        response = Response(status_code=204)
        response.headers["Access-Control-Allow-Origin"] = "*"
        response.headers["Access-Control-Allow-Methods"] = "POST, GET, OPTIONS"
        response.headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization"
        return response

    async def post(self, request):
        try:
            body_bytes = await request.body()
            req_data = json.loads(body_bytes.decode('utf-8'))
        except Exception as e:
            resp = JSONResponse({"error": {"message": f"Invalid JSON body: {str(e)}"}}, status_code=400)
            resp.headers["Access-Control-Allow-Origin"] = "*"
            return resp
        
        provider = req_data.get('provider')
        base_url = req_data.get('baseUrl')
        api_key = req_data.get('apiKey')
        model = req_data.get('model')
        
        # Fallback to secure backend keys
        if not api_key:
            if provider == 'gemini':
                api_key = GEMINI_API_KEY
            elif provider == 'nvidia':
                api_key = NVIDIA_NIM_KEY
            elif provider == 'custom':
                api_key = CUSTOM_API_KEY
        
        is_test = request.url.path == "/api/test"
        
        # Use native Gemini generateContent API to support Google Search Grounding
        if provider == 'gemini' and not is_test:
            gemini_model = model
            if gemini_model.startswith('models/'):
                gemini_model = gemini_model[7:]
            if gemini_model == 'gemini-1.5-flash':
                gemini_model = 'gemini-2.5-flash-lite'
            dest_url = f"https://generativelanguage.googleapis.com/v1beta/models/{gemini_model}:generateContent"
            if api_key:
                dest_url += f"?key={api_key}"
            method = 'POST'
            
            messages = req_data.get('messages', [])
            contents = []
            system_instruction = None
            for msg in messages:
                role = msg.get('role')
                content = msg.get('content')
                if role == 'system':
                    system_instruction = {
                        "parts": [{"text": content}]
                    }
                else:
                    contents.append({
                        "role": 'user' if role == 'user' else 'model',
                        "parts": [{"text": content}]
                    })
            
            req_body = json.dumps({
                "contents": contents,
                "systemInstruction": system_instruction,
                "tools": [{"google_search": {}}],
                "generationConfig": {
                    "maxOutputTokens": req_data.get('max_tokens', 1000),
                    "temperature": req_data.get('temperature', 0.7)
                }
            }).encode('utf-8')
        else:
            # Standard OpenAI-compatible proxy logic
            if is_test:
                dest_url = f"{base_url}/models"
                if provider == 'gemini' and api_key:
                    dest_url += f"?key={api_key}"
                method = 'GET'
                req_body = None
            else:
                dest_url = f"{base_url}/chat/completions"
                if provider == 'gemini' and api_key:
                    dest_url += f"?key={api_key}"
                method = 'POST'
                req_body = json.dumps({
                    "model": model,
                    "messages": req_data.get('messages', []),
                    "max_tokens": req_data.get('max_tokens', 1000),
                    "temperature": req_data.get('temperature', 0.7)
                }).encode('utf-8')

        req = urllib.request.Request(dest_url, data=req_body, method=method)
        req.add_header('Content-Type', 'application/json')
        if api_key and not (provider == 'gemini' and not is_test):
            req.add_header('Authorization', f'Bearer {api_key}')
            
        try:
            with urllib.request.urlopen(req) as response:
                res_data = response.read()
                
                # Convert response back to OpenAI format if using native Gemini API
                if provider == 'gemini' and not is_test:
                    try:
                        gemini_res = json.loads(res_data.decode('utf-8'))
                        text = gemini_res['candidates'][0]['content']['parts'][0]['text']
                        openai_res = {
                            "choices": [
                                {
                                    "message": {
                                        "role": "assistant",
                                        "content": text
                                    }
                                }
                            ]
                        }
                        res_data = json.dumps(openai_res).encode('utf-8')
                    except Exception as e:
                        openai_res = {
                            "choices": [
                                {
                                    "message": {
                                        "role": "assistant",
                                        "content": f"Error parsing response: {str(e)}"
                                    }
                                }
                            ]
                        }
                        res_data = json.dumps(openai_res).encode('utf-8')
                
                resp = Response(res_data, media_type="application/json")
                resp.headers["Access-Control-Allow-Origin"] = "*"
                return resp
        except urllib.error.HTTPError as e:
            # Connection test fallback for models list
            if is_test and e.code in [404, 405]:
                try:
                    dest_url = f"{base_url}/chat/completions"
                    if provider == 'gemini' and api_key:
                        dest_url += f"?key={api_key}"
                    req_body = json.dumps({
                        "model": model,
                        "messages": [{"role": "user", "content": "ping"}],
                        "max_tokens": 1
                    }).encode('utf-8')
                    
                    req2 = urllib.request.Request(dest_url, data=req_body, method='POST')
                    req2.add_header('Content-Type', 'application/json')
                    if api_key and not (provider == 'gemini'):
                        req2.add_header('Authorization', f'Bearer {api_key}')
                        
                    with urllib.request.urlopen(req2) as resp2:
                        res_data2 = resp2.read()
                        resp = Response(res_data2, media_type="application/json")
                        resp.headers["Access-Control-Allow-Origin"] = "*"
                        return resp
                except Exception as e2:
                    resp = JSONResponse({"error": {"message": str(e2)}}, status_code=500)
                    resp.headers["Access-Control-Allow-Origin"] = "*"
                    return resp
            else:
                err_content = e.read() if hasattr(e, 'read') else str(e).encode('utf-8')
                resp = Response(err_content, status_code=e.code, media_type="application/json")
                resp.headers["Access-Control-Allow-Origin"] = "*"
                return resp
        except Exception as e:
            resp = JSONResponse({"error": {"message": str(e)}}, status_code=500)
            resp.headers["Access-Control-Allow-Origin"] = "*"
            return resp

    async def get(self, request):
        if request.url.path == "/api/test":
            resp = JSONResponse({"status": "running"})
            resp.headers["Access-Control-Allow-Origin"] = "*"
            return resp
        resp = Response("Method not allowed", status_code=405)
        resp.headers["Access-Control-Allow-Origin"] = "*"
        return resp

async def starlette_index_endpoint(request):
    return HTMLResponse(HTML_CONTENT)

# Create standalone Starlette app for fallback/local execution
standalone_app = Starlette(routes=[
    Route("/", endpoint=starlette_index_endpoint, methods=["GET"]),
    Route("/index.html", endpoint=starlette_index_endpoint, methods=["GET"]),
    Route("/api/chat", endpoint=StarletteProxyEndpoint, methods=["POST", "OPTIONS"]),
    Route("/api/test", endpoint=StarletteProxyEndpoint, methods=["GET", "POST", "OPTIONS"])
])

# Check if running inside Streamlit (even during startup import phase)
import sys
is_streamlit = 'streamlit' in sys.modules

if is_streamlit:
    import streamlit as st
    from streamlit.runtime.scriptrunner import get_script_run_ctx
    
    # --- STREAMLIT RUN MODE ---
    @st.cache_resource
    def setup_streamlit_api_handler():
        try:
            # Locate the running Starlette app inside Streamlit's process, excluding standalone_app
            streamlit_app = None
            for o in gc.get_referrers(Starlette):
                if o.__class__ is Starlette and o is not standalone_app:
                    if any(r.path in ("/healthz", "/stream", "/_stcore/health", "/_stcore/stream") for r in getattr(o, "routes", [])):
                        streamlit_app = o
                        break
            if streamlit_app is None:
                streamlit_app = next(o for o in gc.get_referrers(Starlette) if o.__class__ is Starlette and o is not standalone_app)
            
            # Check if our routes are already registered to avoid duplicates
            chat_exists = any(r.path == "/api/chat" for r in streamlit_app.routes)
            test_exists = any(r.path == "/api/test" for r in streamlit_app.routes)
            
            if not chat_exists:
                streamlit_app.routes.insert(0, Route("/api/chat", endpoint=StarletteProxyEndpoint, methods=["POST", "OPTIONS"]))
            if not test_exists:
                streamlit_app.routes.insert(0, Route("/api/test", endpoint=StarletteProxyEndpoint, methods=["GET", "POST", "OPTIONS"]))
            print("API routes successfully injected into Streamlit Starlette server!")
        except Exception as e:
            print(f"Failed to inject API routes: {e}")

    # Only run Streamlit UI commands and inject routes when inside an active session context
    ctx = get_script_run_ctx()
    if ctx is not None:
        # Streamlit Page Config (MUST be the first Streamlit command run in the script)
        st.set_page_config(
            page_title="AI Automobile Advisor",
            page_icon="🚗",
            layout="wide",
            initial_sidebar_state="collapsed"
        )

        setup_streamlit_api_handler()

        # Embed the HTML frontend in Streamlit
        st.components.v1.html(
            HTML_CONTENT,
            height=1000,
            scrolling=True
        )
else:
    # --- STANDALONE ASGI RUN MODE ---
    import uvicorn
    print("Starting standalone ASGI web server on http://localhost:8000")
    uvicorn.run(standalone_app, host="0.0.0.0", port=8000)
